VALUES ('tsp-rule-geographic-normalization', 'City / Neighborhood / Address normalization', 'SEMANTIC_NORMALIZATION', 'EXECUTABLE', 'STRUCTURAL_BY_CONSTRUCTION', 'COMPLETE_FOR_DECLARED_FIXTURE', 'O(V)', 'O(V)', 'Every address has exactly one neighborhood and every neighborhood exactly one city.', 'normalized-spatial-hierarchy', 'Promotes city, neighborhood, and address boundaries to first-class rows instead of opaque labels.') ON CONFLICT (tsp_inference_rule_id) DO UPDATE SET display_name = EXCLUDED.display_name, inference_layer = EXCLUDED.inference_layer, implementation_status = EXCLUDED.implementation_status, soundness = EXCLUDED.soundness, completeness = EXCLUDED.completeness, runtime_class = EXCLUDED.runtime_class, memory_class = EXCLUDED.memory_class, applicability = EXCLUDED.applicability, certificate_type = EXCLUDED.certificate_type, description = EXCLUDED.description;

