VALUES ('tsp-rule-tour-witness-validation', 'Ordered Hamiltonian-cycle witness validation', 'CONSTRAINT_CLOSURE', 'EXECUTABLE', 'SOUND_FOR_EXPLICIT_ORDERED_TOUR_WITNESSES', 'COMPLETE_FOR_VALIDATING_A_SUPPLIED_TOUR_NOT_FOR_FINDING_OR_PROVING_OPTIMALITY', 'O(V+E_TOUR)', 'O(V+E_TOUR)', 'Candidate supplies one ordered visit list and one edge-bound leg per required stop.', 'hamiltonian-cycle-witness', 'Derives supplied-tour validity from visit uniqueness, sequence uniqueness, depot placement, edge membership, global one-in/one-out coverage, unique leg order, and route closure.') ON CONFLICT (tsp_inference_rule_id) DO UPDATE SET display_name = EXCLUDED.display_name, inference_layer = EXCLUDED.inference_layer, implementation_status = EXCLUDED.implementation_status, soundness = EXCLUDED.soundness, completeness = EXCLUDED.completeness, runtime_class = EXCLUDED.runtime_class, memory_class = EXCLUDED.memory_class, applicability = EXCLUDED.applicability, certificate_type = EXCLUDED.certificate_type, description = EXCLUDED.description;

