VALUES ('tsp-loop-587', 587, 'Postgres commissioning attempt', 'CLOSED', 'tsp-rule-substrate-commissioning', 'Postgres commissioning attempt', 'Generated Postgres and Python agree on all declared semantics; Decimal-normalized live checks and append-only attempt history close the substrate obligation.', 'Create a first-class inference application spine independent of substrate availability.', 'Run the generated Postgres projection, recreate erb_traveling_salesman, compare vw_* results with Python, and record artifact hashes; otherwise record the exact blocking substrate condition.', 'frontier-postgres-commissioning is OPEN; no execution-run certificate exists', 'Attempts 1-9 preserve missing-CLI, npm, workflow, stale-oracle, chained-finalizer, and numeric-presentation failures. Retry 10 installed the pinned CLI archive, generated the complete vw_* projection, initialized erb_traveling_salesman, passed rulebook-derived Python/Postgres conformance, normalized NUMERIC text through Decimal, and durably sealed the substrate certificate.', 'CLOSED_ON_RETRY_10') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

