VALUES ('tsp-loop-594', 594, 'Degree-two forced-edge closure', 'CLOSED', 'tsp-rule-degree-two-forcing', 'Degree-two forced-edge closure', 'Sparse fixture forced five ring edges from degree-two stops with zero branch decisions; B-D remains for saturation propagation.', 'Propagate degree saturation and proper-subtour forbidden-edge consequences.', 'On a sparse five-stop fixture, stops with exactly two available incident edges force the five cycle edges with zero branching.', 'Degree-two forcing is declared but has no executable state, round, or decision certificates.', 'Sparse fixture forced five ring edges from degree-two stops with zero branch decisions; B-D remains for saturation propagation.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

