VALUES ('tsp-loop-608', 608, 'Component quotient', 'CLOSED', 'tsp-rule-semantic-quotient', 'Component Quotient', 'The city-level object is now a two-node quotient graph; cluster versus component is provenance, while boundary degree and expansion signature carry the semantics.', 'Collapse applications, rounds, supports, antecedents, and decisions into closure events.', 'Represent the two twin neighborhoods as quotient nodes with boundary degree two, unifying cluster and component interfaces.', 'Neighborhood clusters and selected connected components are treated as different kinds of objects despite exposing the same boundary-degree contract.', 'Unified the two neighborhoods and the two selected connected components as quotient nodes with required boundary degree two.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

