VALUES ('tsp-loop-609', 609, 'Closure event', 'CLOSED', 'tsp-rule-closure-event', 'Closure Event', '14 closure events cover selection, union, rigidity, reconstruction, forcing, forbidding, cut parity, repair, optimality, and quotienting.', 'Measure whether new derived vocabulary has stopped increasing the primitive basis.', 'Project representative selection, union, rigidity, reconstruction, forcing, forbidding, cut, repair, optimality, and quotient steps into one closure-event schema.', 'Inference applications, antecedents, supports, states, constraint rounds, and decisions are separate execution concepts.', 'Collapsed applications, states, antecedents, supports, rounds, and decisions into a common closure-event projection.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

