VALUES ('tsp-loop-610', 610, 'Convergence event', 'CLOSED', 'tsp-rule-predicate-invention', 'Convergence Event', 'Convergence event: semantic compression 75%, physical tables 40 to 45, coined terms 14, new primitives after basis discovery 0; status is early empirical support for this finite TSP domain.', 'Stress the eight-predicate basis on larger clusters and branch only after closure leaves a witnessed residual kernel.', 'Certify thirty-two-to-eight semantic compression, fourteen coined terms, zero new primitives after the basis loop, bounded physical schema growth, and an explicit residual kernel.', 'Thirteen reduction loops have coined derived predicates, but their cumulative compression and primitive-basis stability are not certified.', 'Certified a stable eight-predicate basis across fourteen reduction loops: thirty-two baseline surface predicates compress to eight primitives, fourteen useful terms were coined, and no new primitive appeared after loop 598.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

